import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line
} from 'react-konva';
import './AnnotationCanvas.css';

export default function AnnotationCanvas({
  fileUrl,
  annotations,
  onAnnotationsChange,
  selectedTool, // e.g. 'move', 'bbox', 'polygon', etc.
  scale,
  onWheelZoom,
  activeLabelColor
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  // For in-progress shapes
  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      if (containerRef.current) {
        setDims({
          width: containerRef.current.offsetWidth,
          height: containerRef.current.offsetHeight,
        });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Load the image
  useEffect(() => {
    if (!fileUrl) return;
    const img = new Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      setImagePos({ x: 0, y: 0 });
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  // Flatten {x,y} => [x,y,...]
  const flattenPoints = (pts) => pts.flatMap((p) => [p.x, p.y]);

  // -------------- BBox creation --------------
  const startBox = (pos) => {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  };
  const updateBox = (pos) => {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y,
    });
  };
  const finalizeBox = () => {
    if (!newBox) return;
    const newAnn = { type: 'bbox', ...newBox, label: '' };
    // Add logic if you need to check boundaries, etc.
    onAnnotationsChange([...annotations, newAnn]);
    setNewBox(null);
  };

  // -------------- Polygon creation --------------
  const addPolygonPoint = (pos) => {
    setTempPoints((prev) => [...prev, pos]);
    setDrawingPolygon(true);
  };
  const finalizePolygon = () => {
    if (tempPoints.length >= 3) {
      const newAnn = { type: 'polygon', points: tempPoints, label: '' };
      onAnnotationsChange([...annotations, newAnn]);
    }
    setTempPoints([]);
    setDrawingPolygon(false);
  };

  // -------------- Mouse events --------------
  const getGroupPos = (evt) => {
    const group = stageRef.current?.findOne('#anno-group');
    return group ? group.getRelativePointerPosition() : null;
  };

  const handleMouseDown = (evt) => {
    if (selectedTool !== 'move') {
      // Start creating shapes if not in move mode
      const pos = getGroupPos(evt);
      if (!pos) return;
      if (selectedTool === 'bbox') {
        startBox(pos);
      } else if (selectedTool === 'polygon') {
        addPolygonPoint(pos);
      }
      return;
    }
    // If tool is "move", we do nothing special on mouse down.
    // (Konva's draggable will handle background moves.)
  };

  const handleMouseMove = (evt) => {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) updateBox(pos);
    }
    // For polygons, typically we only add points on click, 
    // not on mouse move, so nothing here
  };

  const handleMouseUp = () => {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    }
  };

  const handleDblClick = () => {
    // Double-click to finalize polygon
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    }
  };

  const handleWheel = (evt) => {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  };

  // -------------- Draggable shapes logic --------------
  // For bounding boxes, we'll do an actual <Rect draggable> 
  // For polygons, we'll do a <Group draggable> that contains a <Line>

  // If the user drags a shape, we want to update its position in the "onDragEnd".
  const handleBBoxDragEnd = (index, e) => {
    // New top-left
    const { x, y } = e.target.position();
    const updated = [...annotations];
    const ann = updated[index];
    updated[index] = { ...ann, x, y };
    onAnnotationsChange(updated);
  };

  function DraggablePolygon({ ann, index }) {
    // We'll move the entire polygon as a Group
    // We have to shift all points by the drag offset
    const handleDragEnd = (e) => {
      const { x, y } = e.target.position();
      // Then we reset group to 0,0 but shift all points in the annotation
      const newPoints = ann.points.map(pt => ({
        x: pt.x + x,
        y: pt.y + y,
      }));
      const updated = [...annotations];
      updated[index] = { ...ann, points: newPoints };
      e.target.position({ x: 0, y: 0 }); // Reset group position
      onAnnotationsChange(updated);
    };

    // Cancel bubble so we don't drag the background
    const handleDragStart = (e) => {
      e.cancelBubble = true;
    };

    return (
      <Group
        draggable={selectedTool === 'move'}
        onDragStart={handleDragStart}
        onDragEnd={handleDragEnd}
      >
        <Line
          points={flattenPoints(ann.points)}
          fill={activeLabelColor + '55'}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          closed
        />
      </Group>
    );
  }

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
      >
        <Layer>
          {/* This group holds the image and all shapes */}
          <Group
            id="anno-group"
            draggable={selectedTool === 'move'} // background moves if user clicks empty space
            x={imagePos.x}
            y={imagePos.y}
            onDragEnd={(e) => {
              // user moved the background
              setImagePos({ x: e.target.x(), y: e.target.y() });
            }}
          >
            {/* Render the image */}
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}

            {/* Existing Annotations */}
            {annotations.map((ann, i) => {
              if (ann.type === 'bbox') {
                return (
                  <Rect
                    key={i}
                    x={ann.x}
                    y={ann.y}
                    width={ann.width}
                    height={ann.height}
                    fill={activeLabelColor + '55'}
                    stroke={activeLabelColor}
                    strokeWidth={2 / scale}
                    // Make the Rect itself draggable in move mode
                    draggable={selectedTool === 'move'}
                    onDragStart={(e) => {
                      // Prevent dragging the background
                      e.cancelBubble = true;
                    }}
                    onDragEnd={(e) => handleBBoxDragEnd(i, e)}
                  />
                );
              } else if (ann.type === 'polygon') {
                return (
                  <DraggablePolygon
                    key={i}
                    ann={ann}
                    index={i}
                  />
                );
              }
              return null;
            })}

            {/* In-progress BBox */}
            {newBox && selectedTool === 'bbox' && (
              <Rect
                x={newBox.x}
                y={newBox.y}
                width={newBox.width}
                height={newBox.height}
                fill={activeLabelColor + '55'}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}

            {/* In-progress Polygon (while drawing) */}
            {drawingPolygon && tempPoints.length > 1 && selectedTool === 'polygon' && (
              <Line
                points={flattenPoints([...tempPoints, tempPoints[0]])}
                fill={activeLabelColor + '55'}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
                closed
              />
            )}
          </Group>
        </Layer>
      </Stage>
    </div>
  );
}
